private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 29
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_tuck_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_cleanup_pending() != 41402) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_delete_local() != 22128) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_execute_add() != 43587) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_execute_restore() != 61135) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_list_drives() != 18414) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_load_manifest_entries() != 23479) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_load_pending() != 9541) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_plan_add() != 28908) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_plan_restore() != 56466) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_func_resolve_drive() != 39657) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_method_ffiprogress_start_phase() != 10961) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_method_ffiprogress_advance() != 14437) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_tuck_ffi_checksum_method_ffiprogress_finish_phase() != 37051) {
        return InitializationResult.apiChecksumMismatch
    }

    uniffiCallbackInitFfiProgress()
    return InitializationResult.ok
